
-- Clean up any leftover venue users from failed attempts
DELETE FROM public.profiles WHERE display_name = 'New User' AND created_at > NOW() - INTERVAL '1 hour';
DELETE FROM auth.identities WHERE user_id IN (SELECT id FROM auth.users WHERE email LIKE 'venue-%@afterbefore.rs');
DELETE FROM auth.users WHERE email LIKE 'venue-%@afterbefore.rs';

