    (gen_random_uuid(), 'Concrete Ritual', 'A night of relentless industrial techno. Featuring DJ Petar Lazić and Noctvrne.', v_next_friday, '23:00', '06:00', 'Drugstore', 'Bulevar vojvode Bojovića 30, Belgrade', 44.8124, 20.4570, 500, ARRAY['techno','industrial'], 1000, v_drugstore_uid, 100, 'https://images.unsplash.com/photo-1571266028243-e4733b0f0bb0?w=800'),
